@prefix dcterms: <http://purl.org/dc/terms/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <urn:dde:example-gplates> ;
            sh:resultMessage "DDESoftware profile: metadata record should declare conformance to https://w3id.org/cdif/bbr/metadata/profiles/DDEProfiles/DDESoftware" ;
            sh:resultPath dcterms:conformsTo ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:HasValueConstraintComponent ;
            sh:sourceShape [ sh:hasValue <https://w3id.org/cdif/bbr/metadata/profiles/DDEProfiles/DDESoftware> ;
                    sh:message "DDESoftware profile: metadata record should declare conformance to https://w3id.org/cdif/bbr/metadata/profiles/DDEProfiles/DDESoftware" ;
                    sh:path dcterms:conformsTo ;
                    sh:severity sh:Warning ] ] .

